  1	import { Table, TableVariant, Tbody, Td, Th, Thead, Tr } from '@patternfly/react-table';
  2	import { summaryTitle } from 'pages/Graph/SummaryPanelCommon';
  3	import * as React from 'react';
  4	import { kialiStyle } from 'styles/StyleUtils';
  5	import { renderRateChartHttp, renderRateChartGrpc } from './RateChart';
  6	
  7	const tableStyle = kialiStyle({
  8	  marginBottom: '0.5rem'
  9	});
 10	
 11	type RateTableGrpcPropType = {
 12	  isRequests: boolean;
 13	  rate: number;
 14	  rateGrpcErr: number;
 15	  rateNR: number;
 16	};
 17	
 18	type RateTableTcpPropType = {
 19	  rate: number;
 20	};
 21	
 22	export const RateTableGrpc: React.FC<RateTableGrpcPropType> = (props: RateTableGrpcPropType) => {
 23	  // for the table and graph
 24	  const title = `gRPC Traffic (${props.isRequests ? 'requests' : 'messages'} per second)`;
 25	  const errRate: number = props.rateGrpcErr + props.rateNR;
 26	  const percentErr: number = props.rate === 0 ? 0 : (errRate / props.rate) * 100;
 27	  const percentOK: number = 100 - percentErr;
 28	
 29	  return (
 30	    <div>
 31	      <div className={summaryTitle}>{title}</div>
 32	
 33	      <Table>
 34	        <Thead>
 35	          <Tr>
 36	            <Th dataLabel="Total" textCenter>
 37	              Total
 38	            </Th>
 39	            <Th dataLabel="% Success" textCenter>
 40	              % Success
 41	            </Th>
 42	            <Th dataLabel="% Error" textCenter>
 43	              % Error
 44	            </Th>
 45	          </Tr>
 46	        </Thead>
 47	        <Tbody>
 48	          <Tr>
 49	            <Td dataLabel="Total" textCenter>
 50	              {props.rate.toFixed(2)}
 51	            </Td>
 52	            <Td dataLabel="% Success" textCenter>
 53	              {props.isRequests ? percentOK.toFixed(2) : '-'}
 54	            </Td>
 55	            <Td dataLabel="% Error" textCenter>
 56	              {props.isRequests ? percentErr.toFixed(2) : '-'}
 57	            </Td>
 58	          </Tr>
 59	        </Tbody>
 60	      </Table>
 61	
 62	      {props.isRequests && renderRateChartGrpc(percentOK, percentErr)}
 63	    </div>
 64	  );
 65	};
 66	
 67	type RateTableHttpPropType = {
 68	  title: string;
 69	  rate: number;
 70	  rate3xx: number;
 71	  rate4xx: number;
 72	  rate5xx: number;
 73	  rateNR: number;
 74	};
 75	
 76	export const RateTableHttp: React.FC<RateTableHttpPropType> = (props: RateTableHttpPropType) => {
 77	  // for the table
 78	  const errRate: number = props.rate4xx + props.rate5xx + props.rateNR;
 79	  const percentErr: number = props.rate === 0 ? 0 : (errRate / props.rate) * 100;
 80	  const successErr: number = 100 - percentErr;
 81	
 82	  // for the graph
 83	  const rate2xx: number =
 84	    props.rate === 0 ? 0 : props.rate - props.rate3xx - props.rate4xx - props.rate5xx - props.rateNR;
 85	  const percent2xx: number = props.rate === 0 ? 0 : (rate2xx / props.rate) * 100;
 86	  const percent3xx: number = props.rate === 0 ? 0 : (props.rate3xx / props.rate) * 100;
 87	  const percent4xx: number = props.rate === 0 ? 0 : (props.rate4xx / props.rate) * 100;
 88	  const percent5xx: number = props.rate === 0 ? 0 : (props.rate5xx / props.rate) * 100;
 89	  const percentNR: number = props.rate === 0 ? 0 : (props.rateNR / props.rate) * 100;
 90	
 91	  return (
 92	    <div>
 93	      <div className={summaryTitle}>{props.title}</div>
 94	
 95	      <Table variant={TableVariant.compact} className={tableStyle}>
 96	        <Thead>
 97	          <Tr>
 98	            <Th dataLabel="Total" textCenter>
 99	              Total
100	            </Th>
101	            <Th dataLabel="% Success" textCenter>
102	              % Success
103	            </Th>
104	            <Th dataLabel="% Error" textCenter>
105	              % Error
106	            </Th>
107	          </Tr>
108	        </Thead>
109	        <Tbody>
110	          <Tr>
111	            <Td dataLabel="Total" textCenter>
112	              {props.rate.toFixed(2)}
113	            </Td>
114	            <Td dataLabel="% Success" textCenter>
115	              {successErr.toFixed(2)}
116	            </Td>
117	            <Td dataLabel="% Error" textCenter>
118	              {percentErr.toFixed(2)}
119	            </Td>
120	          </Tr>
121	        </Tbody>
122	      </Table>
123	
124	      {renderRateChartHttp(percent2xx, percent3xx, percent4xx, percent5xx, percentNR)}
125	    </div>
126	  );
127	};
128	
129	export const RateTableTcp: React.FC<RateTableTcpPropType> = (props: RateTableTcpPropType) => {
130	  const title = 'TCP Traffic (bytes per second)';
131	
132	  return (
133	    <div>
134	      <div className={summaryTitle}>{title}</div>
135	
136	      <Table>
137	        <Thead>
138	          <Tr>
139	            <Th dataLabel="Total" textCenter>
140	              Total
141	            </Th>
142	            <Th dataLabel="% Success" textCenter>
143	              % Success
144	            </Th>
145	            <Th dataLabel="% Error" textCenter>
146	              % Error
147	            </Th>
148	          </Tr>
149	        </Thead>
150	        <Tbody>
151	          <Tr>
152	            <Td dataLabel="Total" textCenter>
153	              {props.rate.toFixed(2)}
154	            </Td>
155	            <Td dataLabel="% Success" textCenter>
156	              {'-'}
157	            </Td>
158	            <Td dataLabel="% Error" textCenter>
159	              {'-'}
160	            </Td>
161	          </Tr>
162	        </Tbody>
163	      </Table>
164	    </div>
165	  );
166	};

